(async function() {
  const batchSize = {{batch_size}} || 5;

  // 既に取得した投稿URLを記録（グローバル変数として保持）
  if (!window.__threads_fetched_urls) {
    window.__threads_fetched_urls = new Set();
  }

  const results = [];
  let scrollAttempts = 0;
  const maxScrollAttempts = 10;

  // スクロールしながら投稿を取得
  while (results.length < batchSize && scrollAttempts < maxScrollAttempts) {
    // 現在表示されている投稿要素を取得（投稿コンテナの構造を確認）
    const postContainers = Array.from(document.querySelectorAll('div[data-pressable-container]'));

    for (const container of postContainers) {
      if (results.length >= batchSize) break;

      try {
        // 投稿URLを取得
        const linkEl = container.querySelector('a[href*="/post/"]');
        if (!linkEl) continue;

        let postUrl = linkEl.href || linkEl.getAttribute('href');
        if (!postUrl) continue;

        // 相対URLを絶対URLに変換
        if (postUrl.startsWith('/')) {
          postUrl = window.location.origin + postUrl;
        }

        if (!postUrl.includes('/post/')) continue;

        // 重複チェック
        if (window.__threads_fetched_urls.has(postUrl)) continue;

        // プロモーション/広告判定（スキップしない）
        // const isPromotion = container.querySelector('[aria-label*="プロモーション"], [aria-label*="Promoted"], [data-testid*="promo"], [data-testid*="ad"]') !== null;
        // if (isPromotion) continue;

        // リプライ判定：返信ボタン（svg[aria-label*="返信"]）は全投稿に存在するため使用しない
        // より安全な方法として、「〇〇さんへの返信」「Replying to ...」のようなラベルを探す
        let isReply = false;
        // 方法1: 「さんへの返信」「Replying to」のようなラベルを探す
        const replyLabel = Array.from(container.querySelectorAll('span[dir="auto"]')).find(span => {
          const t = span.textContent || '';
          // 「返信」と「さん」が両方含まれている場合、または「Replying to」が含まれている場合
          return (/返信/.test(t) && /さん/.test(t)) || /Replying to/.test(t);
        });
        if (replyLabel) {
          isReply = true;
        } else {
          // 方法2: URLパターンで判定（/post/.../reply/... のような形式）
          const replyPostLink = container.querySelector('a[href*="/post/"][href*="/reply/"]');
          if (replyPostLink) {
            isReply = true;
          }
        }
        if (isReply) continue;

        // いいね数を取得（修正：SVGの兄弟要素から取得）
        let likeCount = 0;
        const likeButtons = container.querySelectorAll('svg[aria-label*="いいね"], svg[aria-label*="like"], svg[aria-label*="Like"]');
        if (likeButtons.length > 0) {
          const likeButton = likeButtons[0];
          // SVGの親をたどって、次のspan要素を探す
          let current = likeButton;
          for (let i = 0; i < 5; i++) {
            current = current.parentElement;
            if (!current) break;
            // span[dir="auto"]を探す
            const likeSpan = current.querySelector('span[dir="auto"]');
            if (likeSpan) {
              const likeText = likeSpan.textContent || '';
              const match = likeText.match(/([\d,]+)/);
              if (match) {
                likeCount = parseInt(match[1].replace(/,/g, ''), 10) || 0;
                break;
              }
            }
            // 直接のテキストからも試す
            const directText = current.textContent || '';
            if (directText.includes('いいね') || directText.includes('Like')) {
              const match = directText.match(/いいね|Like[\s]*([\d,]+)/);
              if (!match) {
                const numberMatch = directText.match(/([\d,]+)\s*(いいね|Like)/);
                if (numberMatch) {
                  likeCount = parseInt(numberMatch[1].replace(/,/g, ''), 10) || 0;
                  break;
                }
              }
            }
          }
        }

        // いいね数が100未満の場合はスキップ（重要な条件）
        if (likeCount < 100) continue;

        // 本文を取得（最初に見つかった長めのテキスト）
        const textSpans = container.querySelectorAll('span[dir="auto"]');
        let content = '';
        for (const span of textSpans) {
          const text = span.textContent || '';
          const trimmed = text.trim();
          // 本文らしいテキストを取得（20文字以上で、数字だけでない）
          if (trimmed.length > 20 && !/^[\d,\s]+$/.test(trimmed)) {
            content = trimmed;
            break;
          }
        }

        // 本文がない場合はスキップ
        if (!content) continue;

        // 取得済みURLに追加
        window.__threads_fetched_urls.add(postUrl);

        results.push({
          post_url: postUrl,
          content: content,
          like_count: likeCount
        });

      } catch (e) {
        console.error('Error extracting post:', e);
      }
    }

    // 必要な数に達していない場合はスクロール
    if (results.length < batchSize) {
      window.scrollBy(0, window.innerHeight * 2);
      scrollAttempts++;
      // スクロール後の読み込み待機
      await new Promise(r => setTimeout(r, 1500));
    }
  }

  return {
    posts: results,
    count: results.length
  };
})()

(function() {
  // このevalはサーバー側で実行され、pr_search_resultsをDBに保存する
  // サーバー側でpr_search_resultsを取得してDBに保存する処理が実行される
  // 保存結果はサーバー側でpr_save_resultに設定される
  return { message: 'Data will be saved on server side' };
})()

